// // This module implements a 16-bit SRAM with read and write capabilities.
// It has a 16-bit data input (D), a 16-bit data output (Q), an address input (ADDR), a write enable (WE), and a clock signal (CLK).
// When WE is high, the input data D should be written to the memory location specified by ADDR on the falling edge of CLK.
// When WE is low, the data at the memory location specified by ADDR should be output to Q on the falling edge of CLK.
module sram16 (
    input wire [15:0] D,
    input wire [3:0] ADDR,
    input wire WE,
    input wire CLK,
    output reg [15:0] Q
);
    reg [15:0] memory [0:15]; // 16x16-bit memory

    always @(posedge CLK) begin
        if (WE) begin
            memory[ADDR] <= D;  // Write data to memory
        end else begin
            Q <= memory[ADDR];  // Read data from memory
        end
    end
endmodule

